     1→// web/components/layout/sidebar.tsx
     2→"use client";
     3→
     4→import Link from "next/link";
     5→import { usePathname } from "next/navigation";
     6→import {
     7→  LayoutDashboard, FolderKanban, Package, Radio,
     8→  Bell, Megaphone, ChevronLeft, ChevronRight,
     9→} from "lucide-react";
    10→import { cn } from "@/lib/utils";
    11→import { useState } from "react";
    12→
    13→const navItems = [
    14→  { href: "/", label: "Dashboard", icon: LayoutDashboard },
    15→  { href: "/projects", label: "Projects", icon: FolderKanban },
    16→  { href: "/releases", label: "Releases", icon: Package },
    17→  { href: "/sources", label: "Sources", icon: Radio },
    18→  { href: "/subscriptions", label: "Subscriptions", icon: Bell },
    19→  { href: "/channels", label: "Channels", icon: Megaphone },
    20→];
    21→
    22→export function Sidebar() {
    23→  const pathname = usePathname();
    24→  const [collapsed, setCollapsed] = useState(false);
    25→
    26→  return (
    27→    <aside
    28→      className={cn(
    29→        "flex flex-col border-r bg-muted/30 transition-all duration-200",
    30→        collapsed ? "w-16" : "w-56"
    31→      )}
    32→    >
    33→      <div className="flex h-14 items-center border-b px-4">
    34→        {!collapsed && (
    35→          <Link href="/" className="flex items-center gap-2 font-semibold">
    36→            <Package className="h-5 w-5 text-primary" />
    37→            <span>ReleaseBeacon</span>
    38→          </Link>
    39→        )}
    40→        <button
    41→          onClick={() => setCollapsed(!collapsed)}
    42→          className={cn(
    43→            "ml-auto rounded-md p-1 hover:bg-muted",
    44→            collapsed && "mx-auto"
    45→          )}
    46→        >
    47→          {collapsed ? <ChevronRight className="h-4 w-4" /> : <ChevronLeft className="h-4 w-4" />}
    48→        </button>
    49→      </div>
    50→      <nav className="flex-1 space-y-1 p-2">
    51→        {navItems.map((item) => {
    52→          const isActive =
    53→            item.href === "/"
    54→              ? pathname === "/"
    55→              : pathname.startsWith(item.href);
    56→          return (
    57→            <Link
    58→              key={item.href}
    59→              href={item.href}
    60→              className={cn(
    61→                "flex items-center gap-3 rounded-md px-3 py-2 text-sm transition-colors",
    62→                isActive
    63→                  ? "bg-primary/10 text-primary font-medium"
    64→                  : "text-muted-foreground hover:bg-muted hover:text-foreground"
    65→              )}
    66→            >
    67→              <item.icon className="h-4 w-4 shrink-0" />
    68→              {!collapsed && <span>{item.label}</span>}
    69→            </Link>
    70→          );
    71→        })}
    72→      </nav>
    73→    </aside>
    74→  );
    75→}
