                      <td className="px-4 py-2.5 text-[12px] text-[#9ca3af]" style={{ fontFamily: "var(--font-dm-sans)" }}>
                        {timeAgo(rel.released_at)}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
