  return (
    <div
      className="flex gap-0 px-6"
      style={{ borderBottom: "1px solid #e8e8e5" }}
    >
      {TABS.map((t) => (
        <button
          key={t.id}
          onClick={() => onChange(t.id)}
          className="py-3 pr-5 text-[13px] transition-colors duration-100"
          style={{
            fontFamily: "var(--font-dm-sans)",
            color: active === t.id ? "#111113" : "#9ca3af",
