You are implementing Task 2: Global Design Tokens and Typography

## Task Description

**Files:**
- Modify: `web/app/globals.css`
- Modify: `web/app/layout.tsx`

### Step 1: Rewrite `globals.css`

Replace the entire file with the following. This keeps Tailwind 4's `@theme inline` structure, updates the shadcn variable values to match the new design, and adds new design-specific CSS custom properties.

```css
@import "tailwindcss";
@import "tw-animate-css";
@import "shadcn/tailwind.css";
@import "@fontsource/jetbrains-mono/400.css";

@custom-variant dark (&:is(.dark *));

@theme inline {
  --radius-sm: calc(var(--radius) - 4px);
  --radius-md: calc(var(--radius) - 2px);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 4px);

  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-destructive: #dc2626;
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);

  /* Design-system extensions */
  --color-sidebar: var(--sidebar-bg);
  --color-sidebar-text: var(--sidebar-text);
  --color-beacon-accent: var(--beacon-accent);
  --color-mono-bg: var(--mono-bg);
  --color-text-secondary: var(--text-secondary);
  --color-text-muted: var(--text-muted);
  --color-surface: var(--surface);
}

:root {
  --radius: 0.375rem; /* 6px */

  /* Core layout colors */
  --background: #fafaf9;
  --foreground: #111113;
  --surface: #ffffff;
  --sidebar-bg: #16181c;
  --sidebar-text: #9ca3af;
  --beacon-accent: #e8601a;
  --border: #e8e8e5;
  --mono-bg: #f3f3f1;
  --text-secondary: #6b7280;
  --text-muted: #9ca3af;

  /* shadcn variable mappings */
  --card: #ffffff;
  --card-foreground: #111113;
  --primary: #e8601a;
  --primary-foreground: #ffffff;
  --secondary: #f3f3f1;
  --secondary-foreground: #374151;
  --muted: #f3f3f1;
  --muted-foreground: #6b7280;
  --accent: #f3f3f1;
  --accent-foreground: #111113;
  --input: #e8e8e5;
  --ring: #e8601a;

  /* Status colors */
  --status-completed: #16a34a;
  --status-running: #2563eb;
  --status-pending: #d97706;
  --status-failed: #dc2626;
}

@layer base {
  * {
    @apply border-border outline-ring/50;
  }
  body {
    @apply bg-background text-foreground;
    font-family: var(--font-dm-sans), system-ui, sans-serif;
  }
}

/* Motion primitives */
@layer utilities {
  .fade-in {
    animation: fadeIn 150ms ease both;
  }
  @keyframes fadeIn {
    from { opacity: 0; }
    to { opacity: 1; }
  }
}
```

### Step 2: Rewrite `layout.tsx`

Replace Geist fonts with Fraunces + DM Sans. JetBrains Mono is loaded via fontsource CSS import in globals.css.

```tsx
import type { Metadata } from "next";
import { Fraunces, DM_Sans } from "next/font/google";
import { Sidebar } from "@/components/layout/sidebar";
import { Header } from "@/components/layout/header";
import "./globals.css";

const fraunces = Fraunces({
  variable: "--font-fraunces",
  subsets: ["latin"],
  axes: ["SOFT", "WONK"],
  display: "swap",
});

const dmSans = DM_Sans({
  variable: "--font-dm-sans",
  subsets: ["latin"],
  display: "swap",
});

export const metadata: Metadata = {
  title: "ReleaseBeacon",
  description: "Agent-driven release intelligence platform",
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en">
      <body className={`${fraunces.variable} ${dmSans.variable} antialiased`}>
        <div className="flex h-screen">
          <Sidebar />
          <div className="flex flex-1 flex-col overflow-hidden">
            <Header />
            <main className="flex-1 overflow-y-auto p-6 fade-in">{children}</main>
          </div>
        </div>
      </body>
    </html>
  );
}
```

