                      <td className="px-4 py-3">
                        <VersionChip version={rel.version} />
                      </td>
                      <td className="px-4 py-3">
                        <span
                          className="text-[13px] text-[#6b7280]"
                          style={{ fontFamily: "'DM Sans', sans-serif" }}
