  1→"use client";
  2→
  3→import { useState } from "react";
  4→import useSWR from "swr";
  5→import Link from "next/link";
  6→import { releases as releasesApi, projects as projectsApi } from "@/lib/api/client";
  7→import { Card, CardContent } from "@/components/ui/card";
  8→import { Button } from "@/components/ui/button";
  9→import {
 10→  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
 11→} from "@/components/ui/select";
 12→import {
 13→  Table, TableBody, TableCell, TableHead, TableHeader, TableRow,
 14→} from "@/components/ui/table";
 15→import { ChevronLeft, ChevronRight } from "lucide-react";
 16→
 17→export default function ReleasesPage() {
 18→  const [page, setPage] = useState(1);
 19→  const [projectFilter, setProjectFilter] = useState<string>("all");
 20→
 21→  const { data: projectsData } = useSWR("projects-for-filter", () => projectsApi.list());
 22→
 23→  const { data, isLoading } = useSWR(
 24→    ["releases", page, projectFilter],
 25→    () => {
 26→      if (projectFilter !== "all") {
 27→        return releasesApi.listByProject(projectFilter, page);
 28→      }
 29→      // When no project filter, show all releases across all projects
 30→      // The API doesn't have a global releases endpoint, so we use the first project or show empty
 31→      return null;
 32→    }
 33→  );
 34→
 35→  // For the "all projects" case, we need to fetch all project releases
 36→  const { data: allReleasesData } = useSWR(
 37→    projectFilter === "all" ? ["all-releases", page] : null,
 38→    async () => {
 39→      if (!projectsData?.data?.length) return null;
 40→      // Fetch releases from the first project as a default view
 41→      // In production, there would be a global /releases endpoint
 42→      const results = await Promise.all(
 43→        projectsData.data.slice(0, 5).map((p) => releasesApi.listByProject(p.id, page).catch(() => null))
 44→      );
 45→      const allReleases = results
 46→        .filter((r): r is NonNullable<typeof r> => r !== null)
 47→        .flatMap((r) => r.data);
 48→      return allReleases;
 49→    }
 50→  );
 51→
 52→  const displayReleases = projectFilter !== "all" ? data?.data : allReleasesData;
 53→  const total = data?.meta?.total ?? 0;
 54→  const totalPages = Math.max(1, Math.ceil(total / 15));
 55→
 56→  return (
 57→    <div className="space-y-4">
 58→      <div>
 59→        <h2 className="text-lg font-semibold">All Releases</h2>
 60→        <p className="text-sm text-muted-foreground">Browse releases ingested from all sources.</p>
 61→      </div>
 62→
 63→      {/* Filters */}
 64→      <div className="flex gap-3">
 65→        <Select value={projectFilter} onValueChange={(v) => { setProjectFilter(v); setPage(1); }}>
 66→          <SelectTrigger className="w-48">
 67→            <SelectValue placeholder="All Projects" />
 68→          </SelectTrigger>
 69→          <SelectContent>
 70→            <SelectItem value="all">All Projects</SelectItem>
 71→            {projectsData?.data.map((p) => (
 72→              <SelectItem key={p.id} value={p.id}>{p.name}</SelectItem>
 73→            ))}
 74→          </SelectContent>
 75→        </Select>
 76→      </div>
 77→
 78→      <Card>
 79→        <CardContent className="p-0">
 80→          {isLoading ? (
 81→            <div className="py-12 text-center text-muted-foreground">Loading...</div>
 82→          ) : (
 83→            <Table>
 84→              <TableHeader>
 85→                <TableRow>
 86→                  <TableHead>Version</TableHead>
 87→                  <TableHead>Source</TableHead>
 88→                  <TableHead>Released</TableHead>
 89→                  <TableHead>Ingested</TableHead>
 90→                </TableRow>
 91→              </TableHeader>
 92→              <TableBody>
 93→                {(displayReleases ?? []).map((release) => (
 94→                  <TableRow key={release.id}>
 95→                    <TableCell>
 96→                      <Link
 97→                        href={`/releases/${release.id}`}
 98→                        className="font-mono text-sm text-primary hover:underline"
 99→                      >
100→                        {release.version}
101→                      </Link>
102→                    </TableCell>
103→                    <TableCell className="text-xs text-muted-foreground font-mono">
104→                      {release.source_id}
105→                    </TableCell>
106→                    <TableCell className="text-sm text-muted-foreground">
107→                      {release.released_at ? new Date(release.released_at).toLocaleDateString() : "\u2014"}
108→                    </TableCell>
109→                    <TableCell className="text-sm text-muted-foreground">
110→                      {new Date(release.created_at).toLocaleDateString()}
111→                    </TableCell>
112→                  </TableRow>
113→                ))}
114→              </TableBody>
115→            </Table>
116→          )}
117→        </CardContent>
118→      </Card>
119→
120→      {/* Pagination */}
121→      {projectFilter !== "all" && totalPages > 1 && (
122→        <div className="flex items-center justify-between">
123→          <span className="text-sm text-muted-foreground">{total} releases</span>
124→          <div className="flex items-center gap-2">
125→            <Button variant="outline" size="sm" disabled={page <= 1} onClick={() => setPage(page - 1)}>
126→              <ChevronLeft className="h-4 w-4" />
127→            </Button>
128→            <span className="text-sm">Page {page} of {totalPages}</span>
129→            <Button variant="outline" size="sm" disabled={page >= totalPages} onClick={() => setPage(page + 1)}>
130→              <ChevronRight className="h-4 w-4" />
131→            </Button>
132→          </div>
133→        </div>
134→      )}
135→    </div>
136→  );
137→}
