 16→function timeAgo(dateStr: string): string {
 17→  const diff = Date.now() - new Date(dateStr).getTime();
 18→  const mins = Math.floor(diff / 60000);
 19→  if (mins < 60) return `${mins}m ago`;
 20→  const hrs = Math.floor(mins / 60);
 21→  if (hrs < 24) return `${hrs}h ago`;
 22→  return `${Math.floor(hrs / 24)}d ago`;
 23→}
 24→
 25→interface SRRow extends SemanticRelease {
 26→  _projectName?: string;
 27→}
 28→
 29→function SemanticReleasesColumn() {
 30→  const { data: projectsData } = useSWR("projects-for-sr-dashboard", () =>
 31→    projectsApi.list()
 32→  );
 33→
 34→  const { data: allSRs, isLoading } = useSWR(
 35→    projectsData ? "recent-semantic-releases" : null,
 36→    async () => {
 37→      if (!projectsData?.data?.length) return [];
 38→
 39→      const projectMap = new Map(
 40→        projectsData.data.map((p) => [p.id, p.name])
 41→      );
 42→
 43→      const results = await Promise.all(
 44→        projectsData.data.slice(0, 10).map((p) =>
 45→          srApi.list(p.id, 1).catch(() => null)
 46→        )
 47→      );
 48→
 49→      const srs: SRRow[] = results
 50→        .filter((r): r is NonNullable<typeof r> => r !== null)
 51→        .flatMap((r) => r.data)
 52→        .sort(
 53→          (a, b) =>
 54→            new Date(b.created_at).getTime() - new Date(a.created_at).getTime()
 55→        )
 56→        .slice(0, 6)
 57→        .map((sr) => ({
 58→          ...sr,
 59→          _projectName: projectMap.get(sr.project_id),
 60→        }));
 61→
 62→      return srs;
 63→    }
 64→  );
 65→
 66→  return (
 67→    <div
 68→      className="rounded-lg bg-white"
 69→      style={{ border: "1px solid #e8e8e5" }}
 70→    >
 71→      {/* Header */}
 72→      <div
 73→        className="flex items-center justify-between px-5 py-4"
 74→        style={{ borderBottom: "1px solid #e8e8e5" }}
 75→      >
 76→        <h3
 77→          className="font-medium"
 78→          style={{
 79→            fontFamily: "var(--font-dm-sans)",
 80→            fontSize: "13px",
 81→            color: "#1a1a1a",
 82→          }}
 83→        >
 84→          Semantic Releases
 85→        </h3>
 86→        <Link
 87→          href="/projects"
 88→          className="text-sm hover:underline"
 89→          style={{
 90→            fontFamily: "var(--font-dm-sans)",
 91→            fontSize: "13px",
 92→            color: "#e8601a",
 93→          }}
 94→        >
 95→          View all &rarr;
 96→        </Link>
 97→      </div>
 98→
 99→      {/* Body */}
100→      <div className="p-4 space-y-3">
101→        {isLoading ? (
102→          <div
103→            className="py-8 text-center"
104→            style={{
105→              fontFamily: "var(--font-dm-sans)",
106→              fontSize: "13px",
107→              color: "#6b7280",
108→            }}
109→          >
110→            Loading...
111→          </div>
112→        ) : allSRs && allSRs.length > 0 ? (
113→          allSRs.map((sr: SRRow) => (
114→            <Link
115→              key={sr.id}
116→              href={`/projects/${sr.project_id}/semantic-releases/${sr.id}`}
117→              className="block rounded-lg px-4 py-3 transition-colors hover:bg-[#fafaf9]"
118→              style={{ border: "1px solid #e8e8e5" }}
119→            >
120→              <div className="flex items-center justify-between">
121→                <span
122→                  className="font-semibold"
123→                  style={{
124→                    fontFamily: "var(--font-fraunces)",
125→                    fontSize: "15px",
126→                    color: "#1a1a1a",
127→                  }}
128→                >
129→                  {sr._projectName ?? "Unknown Project"}
130→                </span>
131→                <VersionChip version={sr.version} />
132→              </div>
133→              {sr.report?.summary && (
134→                <p
135→                  className="mt-1 line-clamp-1"
136→                  style={{
137→                    fontFamily: "var(--font-dm-sans)",
138→                    fontStyle: "italic",
139→                    fontSize: "13px",
140→                    color: "#6b7280",
141→                  }}
142→                >
143→                  {sr.report.summary}
144→                </p>
145→              )}
146→              <div className="mt-2 flex items-center gap-2">
147→                <StatusDot status={sr.status} />
148→                <span
149→                  style={{
150→                    fontFamily: "var(--font-dm-sans)",
151→                    fontSize: "12px",
152→                    color: "#9ca3af",
153→                  }}
154→                >
155→                  {timeAgo(sr.created_at)}
156→                </span>
157→              </div>
158→            </Link>
159→          ))
160→        ) : (
161→          <div className="py-8 text-center">
162→            <p
163→              style={{
164→                fontFamily: "var(--font-fraunces)",
165→                fontStyle: "italic",
166→                fontSize: "14px",
167→                color: "#9ca3af",
168→              }}
169→            >
170→              No semantic releases yet
171→            </p>
172→          </div>
173→        )}
174→      </div>
175→    </div>
176→  );
