 2→import { cn } from "@/lib/utils";
 3→
 4→interface UrgencyCalloutProps {
 5→  urgency: string;
 6→  description?: string;
 7→  className?: string;
 8→}
 9→
10→export function UrgencyCallout({ urgency, description, className }: UrgencyCalloutProps) {
11→  const upper = urgency?.toUpperCase();
12→  if (upper !== "HIGH" && upper !== "CRITICAL") return null;
13→
14→  const isCritical = upper === "CRITICAL";
15→  const bg = isCritical ? "#fff1f2" : "#fff8f0";
16→  const border = isCritical ? "#dc2626" : "#d97706";
17→  const Icon = isCritical ? AlertCircle : AlertTriangle;
18→
19→  return (
20→    <div
21→      className={cn("rounded px-4 py-3 text-sm", className)}
22→      style={{ backgroundColor: bg, borderLeft: `3px solid ${border}` }}
23→    >
24→      <div className="flex items-start gap-2">
25→        <Icon className="h-4 w-4 mt-0.5 shrink-0" style={{ color: border }} />
26→        <div>
27→          <span className="font-semibold" style={{ color: border }}>
28→            {upper} URGENCY
29→          </span>
30→          {description && (
31→            <p className="mt-0.5 text-[#374151]">{description}</p>
32→          )}
33→        </div>
34→      </div>
35→    </div>
36→  );
37→}
