 12→import { VersionChip } from "@/components/ui/version-chip";
 13→import type { Release, Source, Project } from "@/lib/api/types";
 14→
 15→/* ------------------------------------------------------------------ */
 16→/*  Helpers                                                            */
 17→/* ------------------------------------------------------------------ */
 18→
 19→function timeAgo(dateStr?: string | null): string {
 20→  if (!dateStr) return "\u2014";
 21→  const diff = Date.now() - new Date(dateStr).getTime();
 22→  const mins = Math.floor(diff / 60000);
 23→  if (mins < 60) return `${mins}m ago`;
 24→  const hrs = Math.floor(mins / 60);
 25→  if (hrs < 24) return `${hrs}h ago`;
 26→  return `${Math.floor(hrs / 24)}d ago`;
 27→}
 28→
 29→interface ReleaseRow extends Release {
 30→  _projectName?: string;
 31→  _projectId?: string;
 32→  _provider?: string;
 33→  _repository?: string;
 34→}
 35→
 36→const PER_PAGE = 15;
 37→
 38→/* ------------------------------------------------------------------ */
 39→/*  Page                                                               */
 40→/* ------------------------------------------------------------------ */
 41→
 42→export default function ReleasesPage() {
 43→  const [page, setPage] = useState(1);
 44→  const [projectFilter, setProjectFilter] = useState<string>("all");
 45→
 46→  /* Fetch projects for the filter dropdown + source enrichment */
 47→  const { data: projectsData } = useSWR("projects-for-filter", () =>
 48→    projectsApi.list()
 49→  );
 50→
 51→  /* Build a map: sourceId -> { provider, repository, projectName, projectId } */
 52→  const { data: sourceMap } = useSWR(
 53→    projectsData ? "source-map-for-releases" : null,
 54→    async () => {
 55→      if (!projectsData?.data?.length) return new Map<string, { provider: string; repository: string; projectName: string; projectId: string }>();
 56→      const map = new Map<string, { provider: string; repository: string; projectName: string; projectId: string }>();
 57→      await Promise.all(
 58→        projectsData.data.map(async (p: Project) => {
 59→          const res = await sourcesApi.listByProject(p.id).catch(() => null);
 60→          if (res?.data) {
 61→            for (const s of res.data) {
 62→              map.set(s.id, {
 63→                provider: s.provider,
 64→                repository: s.repository,
 65→                projectName: p.name,
 66→                projectId: p.id,
 67→              });
 68→            }
 69→          }
 70→        })
 71→      );
 72→      return map;
 73→    }
 74→  );
 75→
 76→  /* Fetch releases — scoped by project or aggregated across all */
 77→  const { data: scopedData, isLoading: scopedLoading } = useSWR(
 78→    projectFilter !== "all" ? ["releases", page, projectFilter] : null,
 79→    () => releasesApi.listByProject(projectFilter, page)
 80→  );
 81→
 82→  const { data: allReleasesData, isLoading: allLoading } = useSWR(
 83→    projectFilter === "all" && projectsData
 84→      ? ["all-releases", page]
 85→      : null,
 86→    async () => {
 87→      if (!projectsData?.data?.length) return [];
 88→      const results = await Promise.all(
 89→        projectsData.data.map((p: Project) =>
 90→          releasesApi.listByProject(p.id, page).catch(() => null)
 91→        )
 92→      );
 93→      return results
 94→        .filter((r): r is NonNullable<typeof r> => r !== null)
 95→        .flatMap((r) => r.data)
 96→        .sort(
 97→          (a, b) =>
 98→            new Date(b.created_at).getTime() - new Date(a.created_at).getTime()
 99→        );
100→    }
101→  );
102→
103→  const isLoading = projectFilter !== "all" ? scopedLoading : allLoading;
104→
105→  /* Enrich releases with source metadata */
106→  const rawReleases: Release[] =
107→    projectFilter !== "all"
108→      ? scopedData?.data ?? []
109→      : allReleasesData ?? [];
110→
111→  const releases: ReleaseRow[] = rawReleases.map((r) => {
112→    const info = sourceMap?.get(r.source_id);
113→    return {
114→      ...r,
115→      _projectName: info?.projectName,
116→      _projectId: info?.projectId,
117→      _provider: info?.provider,
118→      _repository: info?.repository,
119→    };
120→  });
121→
122→  /* Pagination math */
123→  const total = projectFilter !== "all" ? (scopedData?.meta?.total ?? 0) : releases.length;
124→  const totalPages = Math.max(1, Math.ceil(total / PER_PAGE));
125→  const startRow = (page - 1) * PER_PAGE + 1;
126→  const endRow = Math.min(page * PER_PAGE, total);
127→
128→  return (
129→    <div className="space-y-6">
130→      {/* Page title */}
131→      <h1
132→        style={{
133→          fontFamily: "var(--font-fraunces)",
134→          fontSize: "24px",
135→          fontWeight: 700,
136→          color: "#1a1a1a",
137→        }}
138→      >
139→        Releases
140→      </h1>
141→
142→      {/* Project filter */}
143→      <div>
144→        <select
145→          value={projectFilter}
146→          onChange={(e) => {
147→            setProjectFilter(e.target.value);
148→            setPage(1);
149→          }}
150→          className="appearance-none rounded-md bg-white px-3 py-2 pr-8 outline-none transition-shadow"
151→          style={{
152→            fontFamily: "var(--font-dm-sans)",
153→            fontSize: "13px",
154→            color: "#1a1a1a",
155→            border: "1px solid #e8e8e5",
156→          }}
157→          onFocus={(e) =>
158→            (e.currentTarget.style.boxShadow = "0 0 0 2px #e8601a40")
159→          }
160→          onBlur={(e) => (e.currentTarget.style.boxShadow = "none")}
161→        >
162→          <option value="all">All Projects</option>
163→          {projectsData?.data.map((p: Project) => (
164→            <option key={p.id} value={p.id}>
165→              {p.name}
166→            </option>
167→          ))}
168→        </select>
169→      </div>
170→
171→      {/* Table card */}
172→      <div
173→        className="overflow-hidden rounded-lg bg-white"
174→        style={{ border: "1px solid #e8e8e5" }}
175→      >
176→        {isLoading ? (
177→          <div
178→            className="py-16 text-center"
179→            style={{
180→              fontFamily: "var(--font-dm-sans)",
181→              fontSize: "13px",
182→              color: "#6b7280",
183→            }}
184→          >
185→            Loading...
186→          </div>
187→        ) : releases.length === 0 ? (
188→          <div className="py-16 text-center">
189→            <p
190→              style={{
191→                fontFamily: "var(--font-fraunces)",
192→                fontStyle: "italic",
193→                fontSize: "15px",
194→                color: "#9ca3af",
195→              }}
196→            >
197→              No releases ingested yet
198→            </p>
199→          </div>
200→        ) : (
201→          <table className="w-full">
202→            <thead>
203→              <tr style={{ borderBottom: "1px solid #e8e8e5", backgroundColor: "#fafaf9" }}>
204→                {["Project", "Provider", "Repository", "Version", "Released", "Age"].map(
205→                  (col) => (
206→                    <th
207→                      key={col}
208→                      className="px-4 py-3 text-left"
209→                      style={{
210→                        fontFamily: "var(--font-dm-sans)",
211→                        fontSize: "11px",
212→                        fontWeight: 600,
213→                        textTransform: "uppercase" as const,
214→                        letterSpacing: "0.05em",
215→                        color: "#9ca3af",
216→                      }}
217→                    >
218→                      {col}
219→                    </th>
220→                  )
221→                )}
222→              </tr>
223→            </thead>
224→            <tbody>
225→              {releases.map((release) => (
226→                <tr
227→                  key={release.id}
228→                  className="transition-colors hover:bg-[#fafaf9]"
229→                  style={{ borderBottom: "1px solid #e8e8e5" }}
230→                >
231→                  {/* Project */}
232→                  <td className="px-4 py-3">
233→                    {release._projectId ? (
234→                      <Link
235→                        href={`/projects/${release._projectId}`}
236→                        className="hover:underline"
237→                        style={{
238→                          fontFamily: "var(--font-dm-sans)",
239→                          fontSize: "13px",
240→                          color: "#1a1a1a",
241→                          fontWeight: 500,
242→                        }}
243→                      >
244→                        {release._projectName ?? "\u2014"}
245→                      </Link>
246→                    ) : (
247→                      <span
248→                        style={{
249→                          fontFamily: "var(--font-dm-sans)",
250→                          fontSize: "13px",
251→                          color: "#9ca3af",
252→                        }}
253→                      >
254→                        {"\u2014"}
255→                      </span>
256→                    )}
257→                  </td>
258→
259→                  {/* Provider */}
260→                  <td className="px-4 py-3">
261→                    {release._provider ? (
262→                      <ProviderBadge provider={release._provider} />
263→                    ) : (
264→                      <span
265→                        style={{
266→                          fontFamily: "var(--font-dm-sans)",
267→                          fontSize: "13px",
268→                          color: "#9ca3af",
269→                        }}
270→                      >
271→                        {"\u2014"}
272→                      </span>
273→                    )}
274→                  </td>
275→
276→                  {/* Repository */}
277→                  <td className="px-4 py-3">
278→                    <span
279→                      style={{
280→                        fontFamily: "'JetBrains Mono', monospace",
