282→                        color: "#374151",
283→                      }}
284→                    >
285→                      {release._repository ?? release.source_id}
286→                    </span>
287→                  </td>
288→
289→                  {/* Version */}
290→                  <td className="px-4 py-3">
291→                    <Link href={`/releases/${release.id}`}>
