318→                      }}
319→                    >
320→                      {timeAgo(release.released_at ?? release.created_at)}
321→                    </span>
322→                  </td>
323→                </tr>
324→              ))}
325→            </tbody>
326→          </table>
327→        )}
328→      </div>
329→
330→      {/* Pagination */}
331→      {total > 0 && (
332→        <div className="flex items-center justify-between">
