 14→import { ArrowLeft } from "lucide-react";
 15→
 16→/* ------------------------------------------------------------------ */
 17→/*  Helpers                                                            */
 18→/* ------------------------------------------------------------------ */
 19→
 20→function timeAgo(dateStr?: string | null): string {
 21→  if (!dateStr) return "\u2014";
 22→  const diff = Date.now() - new Date(dateStr).getTime();
 23→  const mins = Math.floor(diff / 60000);
 24→  if (mins < 60) return `${mins}m ago`;
 25→  const hrs = Math.floor(mins / 60);
 26→  if (hrs < 24) return `${hrs}h ago`;
 27→  return `${Math.floor(hrs / 24)}d ago`;
 28→}
 29→
 30→/* ------------------------------------------------------------------ */
 31→/*  Component                                                          */
 32→/* ------------------------------------------------------------------ */
 33→
 34→export function ReleaseDetail({ id }: { id: string }) {
 35→  /* Fetch release */
 36→  const { data: releaseData, isLoading } = useSWR(`release-${id}`, () =>
 37→    releasesApi.get(id)
 38→  );
 39→
 40→  const release = releaseData?.data;
 41→
 42→  /* Fetch source info once we have the release */
 43→  const { data: sourceData } = useSWR(
 44→    release ? `source-${release.source_id}` : null,
 45→    () => (release ? sourcesApi.get(release.source_id) : null)
 46→  );
 47→  const source: Source | undefined = sourceData?.data;
 48→
 49→  /* Fetch project info once we have the source */
 50→  const { data: projectData } = useSWR(
 51→    source ? `project-${source.project_id}` : null,
 52→    () => (source ? projectsApi.get(source.project_id) : null)
 53→  );
 54→  const project: Project | undefined = projectData?.data;
 55→
 56→  /* Fetch linked semantic releases (via project) */
 57→  const { data: srData } = useSWR(
 58→    source ? `sr-for-release-${id}` : null,
 59→    async () => {
 60→      if (!source) return [];
 61→      const res = await srApi.list(source.project_id, 1).catch(() => null);
 62→      if (!res?.data) return [];
 63→      /* Filter semantic releases whose version matches this release version */
 64→      return res.data.filter((sr: SemanticRelease) => sr.version === release?.version);
 65→    }
 66→  );
 67→
 68→  const linkedSRs: SemanticRelease[] = srData ?? [];
 69→
 70→  /* Loading state */
 71→  if (isLoading) {
 72→    return (
 73→      <div
 74→        className="py-16 text-center"
 75→        style={{
 76→          fontFamily: "var(--font-dm-sans)",
 77→          fontSize: "13px",
 78→          color: "#6b7280",
 79→        }}
 80→      >
 81→        Loading...
 82→      </div>
 83→    );
 84→  }
 85→
 86→  if (!release) {
 87→    return (
 88→      <div className="py-16 text-center">
 89→        <p
 90→          style={{
 91→            fontFamily: "var(--font-fraunces)",
 92→            fontStyle: "italic",
 93→            fontSize: "15px",
 94→            color: "#9ca3af",
 95→          }}
 96→        >
 97→          Release not found
 98→        </p>
 99→      </div>
100→    );
101→  }
102→
103→  return (
104→    <div className="space-y-8">
105→      {/* Back link */}
106→      <Link
107→        href="/releases"
108→        className="inline-flex items-center gap-1.5 transition-colors hover:opacity-70"
109→        style={{
110→          fontFamily: "var(--font-dm-sans)",
111→          fontSize: "13px",
112→          color: "#6b7280",
113→        }}
