117→      _provider: info?.provider,
118→      _repository: info?.repository,
119→    };
120→  });
121→
122→  /* Pagination math */
123→  const total = projectFilter !== "all" ? (scopedData?.meta?.total ?? 0) : releases.length;
124→  const totalPages = Math.max(1, Math.ceil(total / PER_PAGE));
125→  const startRow = (page - 1) * PER_PAGE + 1;
126→  const endRow = Math.min(page * PER_PAGE, total);
127→
128→  return (
129→    <div className="space-y-6">
130→      {/* Page title */}
131→      <h1
132→        style={{
133→          fontFamily: "var(--font-fraunces)",
134→          fontSize: "24px",
135→          fontWeight: 700,
136→          color: "#1a1a1a",
137→        }}
138→      >
139→        Releases
