151→          style={{
152→            fontFamily: "var(--font-dm-sans)",
153→            fontSize: "13px",
154→            color: "#1a1a1a",
155→            border: "1px solid #e8e8e5",
156→          }}
157→          onFocus={(e) =>
158→            (e.currentTarget.style.boxShadow = "0 0 0 2px #e8601a40")
159→          }
160→          onBlur={(e) => (e.currentTarget.style.boxShadow = "none")}
161→        >
162→          <option value="all">All Projects</option>
163→          {projectsData?.data.map((p: Project) => (
164→            <option key={p.id} value={p.id}>
165→              {p.name}
166→            </option>
167→          ))}
168→        </select>
169→      </div>
170→
171→      {/* Table card */}
172→      <div
